// Load Google Cloud and notification config from n8n environment variables.
// These must be set in the n8n instance (Settings → Environment Variables)
// or via the N8N_ENVIRONMENT_VARIABLES docker env.

const config = {
  projectId:        $env.GOOGLE_CLOUD_PROJECT_ID        || '',
  location:         $env.GOOGLE_CLOUD_LOCATION          || 'us-central1',
  runtimeTemplate:  $env.GOOGLE_CLOUD_NOTEBOOK_RUNTIME_TEMPLATE || '',
  notebookGcsUri:   $env.COLAB_NOTEBOOK_GCS_URI         || '',
  outputGcsPrefix:  $env.COLAB_OUTPUT_GCS_PREFIX         || '',
  dataTeamEmail:    $env.DATA_TEAM_EMAIL                 || 'data-team@novaseat.dev',
  alertFromEmail:   $env.ALERT_FROM_EMAIL                || 'noreply@novaseat.dev',
  scoringRunId:     $input.first().json.id,
  scoringRunStart:  $input.first().json.started_at,
};

if (!config.projectId || !config.notebookGcsUri) {
  throw new Error(
    'Missing required env vars: GOOGLE_CLOUD_PROJECT_ID and COLAB_NOTEBOOK_GCS_URI must be set in n8n environment variables.'
  );
}

return [{ json: config }];

// Generate a Google access token from a Service Account key.
// Requires n8n env vars: GOOGLE_SA_CLIENT_EMAIL and GOOGLE_SA_PRIVATE_KEY
//
// GOOGLE_SA_PRIVATE_KEY must be the full PEM private key from the JSON key file.
// In docker-compose, use a single-line version with literal \n characters.

const crypto = require('crypto');

const clientEmail = $env.GOOGLE_SA_CLIENT_EMAIL || '';
const privateKey = ($env.GOOGLE_SA_PRIVATE_KEY || '').replace(/\\n/g, '\n');

if (!clientEmail || !privateKey) {
  throw new Error(
    'Missing GOOGLE_SA_CLIENT_EMAIL or GOOGLE_SA_PRIVATE_KEY in n8n environment variables.'
  );
}

const scope = 'https://www.googleapis.com/auth/cloud-platform';
const now = Math.floor(Date.now() / 1000);

// Build JWT header and claim set
const header = { alg: 'RS256', typ: 'JWT' };
const claimSet = {
  iss: clientEmail,
  scope: scope,
  aud: 'https://oauth2.googleapis.com/token',
  iat: now,
  exp: now + 3600,
};

function base64url(obj) {
  return Buffer.from(JSON.stringify(obj))
    .toString('base64')
    .replace(/=/g, '')
    .replace(/\+/g, '-')
    .replace(/\//g, '_');
}

const unsignedJwt = base64url(header) + '.' + base64url(claimSet);

// Sign with RSA-SHA256
const sign = crypto.createSign('RSA-SHA256');
sign.update(unsignedJwt);
const signature = sign.sign(privateKey, 'base64')
  .replace(/=/g, '')
  .replace(/\+/g, '-')
  .replace(/\//g, '_');

const jwt = unsignedJwt + '.' + signature;

// Exchange JWT for access token
const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://oauth2.googleapis.com/token',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: `grant_type=urn%3Aietf%3Aparams%3Aoauth%3Agrant-type%3Ajwt-bearer&assertion=${jwt}`,
});

if (!response.access_token) {
  throw new Error('Failed to obtain access token: ' + JSON.stringify(response));
}

const config = $input.first().json;
return [{ json: { ...config, accessToken: response.access_token, saClientEmail: clientEmail } }];

// Extract the execution job name from the API response for polling.
// The API may return an operation wrapper (jobs/.../operations/...).
// Strip the /operations/... suffix to get the actual job resource name.
const response = $input.first().json;
const config = $('Get Access Token').first().json;

let jobName = response.name || '';
if (jobName.includes('/operations/')) {
  jobName = jobName.split('/operations/')[0];
}

return [{
  json: {
    ...config,
    executionJobName: jobName,
    executionJobState: response.jobState || 'PENDING',
  }
}];

// Check if the notebook execution has completed, failed, or is still running.
// The Vertex AI API returns the state in the 'jobState' field
// with values like JOB_STATE_SUCCEEDED, JOB_STATE_RUNNING, etc.
const response = $input.first().json;
const config = $('Get Access Token').first().json;
const rawState = (response.jobState || 'UNKNOWN').toUpperCase();

const terminalStates = ['JOB_STATE_SUCCEEDED', 'JOB_STATE_FAILED', 'JOB_STATE_CANCELLED', 'JOB_STATE_EXPIRED'];
const isComplete = rawState === 'JOB_STATE_SUCCEEDED';
const isFailed = ['JOB_STATE_FAILED', 'JOB_STATE_CANCELLED', 'JOB_STATE_EXPIRED'].includes(rawState);
const isRunning = !terminalStates.includes(rawState);

return [{
  json: {
    ...config,
    executionState: rawState,
    isComplete,
    isFailed,
    isRunning,
    gcsOutputUri: response.gcsOutputUri || '',
    error: response.error || null,
  }
}];

// Download scored_accounts.csv from GCS and build an upsert SQL.
const accessToken = $('Get Access Token').item.json.accessToken;
const gcsUri = ($env.COLAB_NOTEBOOK_GCS_URI || '').replace(/\/[^\/]+$/, '');
const csvGcsUri = gcsUri.replace('gs://', '').replace(/\/Colab.*/, '') + '/artifacts/scored_accounts.csv';
const bucket = csvGcsUri.split('/')[0];
const object = csvGcsUri.split('/').slice(1).join('/');

// 1. Download the CSV from GCS
const csvText = await this.helpers.httpRequest({
  method: 'GET',
  url: `https://storage.googleapis.com/storage/v1/b/${bucket}/o/${encodeURIComponent(object)}?alt=media`,
  headers: { Authorization: `Bearer ${accessToken}` },
  json: false,
});

if (!csvText || !String(csvText).trim()) {
  throw new Error('scored_accounts.csv is empty or not found on GCS');
}

// 2. Parse CSV (handles quoted fields containing commas and escaped quotes)
const lines = String(csvText).trim().split('\n');
const headers = lines[0].split(',').map(h => h.trim().replace(/^\"|\"$/g, ''));
const rows = [];

for (let i = 1; i < lines.length; i++) {
  if (!lines[i].trim()) continue;
  const line = lines[i];
  const row = {};
  let field = '';
  let inQuotes = false;
  let colIdx = 0;

  for (let j = 0; j < line.length; j++) {
    const ch = line[j];
    if (inQuotes) {
      if (ch === '"') {
        if (j + 1 < line.length && line[j + 1] === '"') {
          field += '"';
          j++;
        } else {
          inQuotes = false;
        }
      } else {
        field += ch;
      }
    } else {
      if (ch === '"') {
        inQuotes = true;
      } else if (ch === ',') {
        row[headers[colIdx]] = field;
        field = '';
        colIdx++;
      } else {
        field += ch;
      }
    }
  }
  row[headers[colIdx]] = field;
  rows.push(row);
}

if (rows.length === 0) {
  throw new Error('scored_accounts.csv parsed but contains no data rows');
}

// 3. Build upsert SQL
const esc = (s) => s == null ? 'NULL' : "'" + String(s).replace(/'/g, "''") + "'";

const values = rows.map(r => {
  if (!r.name) return null;
  const name = esc(r.name);
  const prob = parseFloat(r.churn_probability) || 0;
  const tier = esc(r.risk_tier || 'Low') + '::risk_tier';
  const drivers = r.churn_drivers ? esc(r.churn_drivers) + '::jsonb' : 'NULL';
  const scoredAt = r.last_scored_at ? esc(r.last_scored_at) + '::timestamptz' : 'NOW()';
  return `(${name}, ${prob}, ${tier}, ${drivers}, ${scoredAt})`;
}).filter(Boolean).join(',\n  ');

if (!values) {
  throw new Error('No valid rows with a name column found in scored_accounts.csv — cannot build upsert query');
}

const sql = `UPDATE accounts AS a SET\n  churn_probability = v.churn_probability,\n  risk_tier = v.risk_tier,\n  churn_drivers = v.churn_drivers,\n  last_scored_at = v.last_scored_at\nFROM (VALUES\n  ${values}\n) AS v(name, churn_probability, risk_tier, churn_drivers, last_scored_at)\nWHERE a.name = v.name;`;

return [{ json: { sql, rowCount: rows.length } }];
